import React from 'react';
import { Menu as MenuIcon, Globe, Sun, Moon, LogOut } from 'lucide-react';
import { useApp, useAppActions } from '../context/AppContext';
import '../styles/globals.css';

const Header: React.FC = () => {
  const { state } = useApp();
  const { toggleSidebar, changeLanguage, changeTheme, setLogin } = useAppActions();

  const handleLogout = () => {
    setLogin(false);
  };

  return (
    <header 
      className="h-16 px-4 flex items-center justify-between border-b shrink-0"
      style={{
        backgroundColor: 'var(--color-surface)',
        borderColor: 'var(--color-border)'
      }}
    >
      <div className="flex items-center gap-4">
                <div className="flex items-center gap-2">
          <div className="w-8 h-8 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-lg flex items-center justify-center text-white font-bold text-sm shadow-md">eC</div>
          <span className="font-bold text-lg hide-mobile">enContact</span>
        </div>
      </div>

      <div className="flex items-center gap-2">
        <button 
          onClick={changeLanguage} 
          className="btn btn-ghost btn-icon"
          aria-label="Change language"
        >
          <Globe size={18} />
          <span className="text-xs uppercase">{state.language}</span>
        </button>
        <button 
          onClick={changeTheme} 
          className="btn btn-ghost btn-icon"
          aria-label="Toggle theme"
        >
          {state.theme === 'dark' ? <Sun size={18} /> : <Moon size={18} />}
        </button>
        <button 
          onClick={handleLogout}
          className="btn btn-ghost btn-icon"
          aria-label="Logout"
        >
          <LogOut size={18} />
        </button>
      </div>
    </header>
  );
};

export default Header;
